import{_ as t,o as r,c as e,a2 as l}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F11: 處分重大資產與資本配置 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F11_處分重大資產與資本配置_投資研究員.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F11_處分重大資產與資本配置_投資研究員.md"}'),i={name:"審計報告庫/財務審計/8064_東捷/20260429/F11_處分重大資產與資本配置_投資研究員.md"};function o(n,a,s,h,_,c){return r(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="f11-處分重大資產與資本配置-投資研究員-審計報告" tabindex="-1">F11: 處分重大資產與資本配置 - 投資研究員 審計報告 <a class="header-anchor" href="#f11-處分重大資產與資本配置-投資研究員-審計報告" aria-label="Permalink to &quot;F11: 處分重大資產與資本配置 - 投資研究員 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>是否存在處分重大資產（如土地、專利、子公司）之行為？處分損益佔比為何？資金用途是投入再投資還是為了彌補虧損？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p><strong>根據截至 2025 年最新公開數據：</strong> 2023年新和廠處分利益佔淨利14.84%、本業營利率僅0.47%；2025年本業純度已翻轉至97.4%，屬救急→回血→轉骨之中期改善。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>評級：B+（轉型改善中，歷史包袱明確）</strong></li><li><strong>重點數據</strong>：2023年業外貢獻92.5%獲利；2025年本業營利率7.63%，獲利純度97.4%；CapEx從1,002萬回升至5,709萬</li><li><strong>診斷見解</strong>：2022-2023年東捷逢顯示器下行，被迫售地+清算子公司補充現金流；2024年轉型半導體先進封裝設備後本業回血。處分行爲屬「被動資產活化」，非健康資本配置。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-獲利含金量穿透" tabindex="-1">1. 獲利含金量穿透 <a class="header-anchor" href="#_1-獲利含金量穿透" aria-label="Permalink to &quot;1. 獲利含金量穿透&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2022→2025年營利率波動：5.13%→0.47%(2023谷底)→3.08%→7.63%(2025)。2023年處分新和廠利益27,538千元佔淨利14.84%；扣除後當年僅營利1,394萬。2025年非經常項僅子公司清算損失10,394千元(-4.6%)與商譽減損2,021千元，本業貢獻度達97.4%，近四年最純淨。</li><li><strong>深度見解</strong>：2023年若無售地入帳，EPS將由0.96降至約0.82。2025年半導體設備佔比逾30%後營利率顯著拉升，獲利含金量大增。</li></ul><h3 id="_2-戰略意圖判別" tabindex="-1">2. 戰略意圖判別 <a class="header-anchor" href="#_2-戰略意圖判別" aria-label="Permalink to &quot;2. 戰略意圖判別&quot;">​</a></h3><ul><li><strong>核心重點</strong>：①2022年出售博隆(21,000千元)→聚焦本業。②2023年出售新和廠(38,886千元)，營收年減23.7%，CapEx縮至1,002萬→「現金求生」。③2024年斥2.65億購入金融債券(票面3.7%-5.8%)→閒置資金充裕，轉固定收益配置。④2025年清算Far Tech(損失10,394千元)+期後決議出售漢錸(42,000千元/2026交割)。</li><li><strong>深度見解</strong>：2022-2023年爲生存防禦：售地、砍子公司、壓CapEx。2024年起轉擴張：加大半導體設備投入，購債活化資金。2025年股利0.70→1.10元，出現兼顧股東回饋混合信號。</li></ul><h3 id="_3-資產結構變動" tabindex="-1">3. 資產結構變動 <a class="header-anchor" href="#_3-資產結構變動" aria-label="Permalink to &quot;3. 資產結構變動&quot;">​</a></h3><ul><li><strong>核心重點</strong>：總資產69.49→56.09億(-19.3%)，主因庫存去化+售廠。PPE由9.86降至4.50億(-54.4%)。投資性不動產0→4.03億(自用轉出租)。金融資產投資0.79→4.29億(購債)。ROE：11.0%→5.0%→4.3%→7.0%(回升)。</li><li><strong>深度見解</strong>：資產結構從重轉輕。2023年處分舊廠後將自用資產轉收租(年租金2,544萬)，形成可持續現金流，優於一次性售地利益。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一【資本配置盲目】</strong>：2024年斥2.65億購保險公司次順位債，同期本業營利僅8,011萬。大量閒置資金轉長天期債券而非投入本業，若半導體轉型不如預期，指向管理層對本業前景信心不足。</li><li><strong>空頭風險二【頻繁處分暗示治理風險】</strong>：三年處理三家子公司(博隆/寧波東捷/漢錸)+一廠房(新和廠)+一清算(Far Tech)，顯示過往多角化失敗。2026年漢錸出售後集團規模持續縮減，存在「越賣越小」空殼化風險。</li><li><strong>空頭風險三【匯兌波動本質未除】</strong>：2022-2024年匯兌各爲+254,415/+13,112/+86,140千元，2025年轉-768千元。東捷大量美元資產與債券與匯率掛鉤，美元若走弱將同時衝擊匯兌與債券評價。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>年報</strong>: OK — 2023_Q4（112年度）、2024_Q4（113年度）、2025_Q4（114年度）合併財務報告，附註十六/十七/二六/三十/三五</li><li><strong>yfinance (8064.TWO)</strong>: OK — 年/季度損益表、資產負債表、現金流量表完整</li><li><strong>MOPS 重大訊息</strong>: 未獲取具體公告 ID（搜尋引擎未檢索到正式MOPS公告），數據以年報附註爲主</li><li><strong>關鍵核對碼</strong>: <ul><li>2023年新和廠處分利益 27,538 千元（附註十六/二六）</li><li>2024年債券投資 265,120 千元（附註九，現金流量表）</li><li>2025年 Far Tech 清算損失 10,394 千元（附註三十）</li><li>2026年漢錸出售價款 42,000 千元（附註三五，期後事項）</li></ul></li></ul>',19)])])}const g=t(i,[["render",o]]);export{u as __pageData,g as default};
